@media only screen and (max-width: @largestMobileScreen) {
  .ui.container {
    width: @mobileWidth !important;
    margin-left: @mobileGutter !important;
    margin-right: @mobileGutter !important;
  }
  .ui.grid.container {
    width: @mobileGridWidth !important;
  }
  .ui.relaxed.grid.container {
    width: @mobileRelaxedGridWidth !important;
  }
  .ui.very.relaxed.grid.container {
    width: @mobileVeryRelaxedGridWidth !important;
  }
}

@media only screen and (max-width: @largestMobileScreen) {
    .ui.scrolling.dropdown .menu,
    .ui.dropdown .scrolling.menu {
        max-height: @scrollingMobileMaxMenuHeight;
    }
    & when (@variationDropdownResizable) {
        .ui.scrolling.resizable.dropdown .menu,
        .ui.dropdown .scrolling.resizable.menu {
            height: @scrollingMobileMaxMenuHeight;
        }
    }
}

@media only screen and (min-width: @tabletBreakpoint) {
    .ui.scrolling.dropdown .menu,
    .ui.dropdown .scrolling.menu {
        max-height: @scrollingTabletMaxMenuHeight;
    }
    & when (@variationDropdownResizable) {
        .ui.scrolling.resizable.dropdown .menu,
        .ui.dropdown .scrolling.resizable.menu {
            height: @scrollingTabletMaxMenuHeight;
        }
    }
}

@media only screen and (min-width: @computerBreakpoint) {
    .ui.scrolling.dropdown .menu,
    .ui.dropdown .scrolling.menu {
        max-height: @scrollingComputerMaxMenuHeight;
    }
    & when (@variationDropdownResizable) {
        .ui.scrolling.resizable.dropdown .menu,
        .ui.dropdown .scrolling.resizable.menu {
            height: @scrollingComputerMaxMenuHeight;
        }
    }
}

@media only screen and (min-width: @widescreenMonitorBreakpoint) {
    .ui.scrolling.dropdown .menu,
    .ui.dropdown .scrolling.menu {
        max-height: @scrollingWidescreenMaxMenuHeight;
    }
    & when (@variationDropdownResizable) {
        .ui.scrolling.resizable.dropdown .menu,
        .ui.dropdown .scrolling.resizable.menu {
            height: @scrollingWidescreenMaxMenuHeight;
        }
    }
}

&.active,
  &.active:hover,
  &.active:focus {
    z-index: 2; // Place active items above their siblings for proper border styling
    color: @list-group-active-color;
    background-color: @list-group-active-bg;
    border-color: @list-group-active-border;

    // Force color to inherit for custom content
    .list-group-item-heading {
      color: inherit;
    }
    .list-group-item-text {
      color: lighten(@list-group-active-bg, 40%);
    }
  }

body.with-panel-left-reveal, body.with-panel-right-reveal {
    .views {
        .transition(@panelsDuration);
        -webkit-transition-property: -webkit-transform;
        -moz-transition-property: -moz-transform;
        transition-property: transform;
    }
    .panel.not-animated ~ .views {
        .transition(0ms);
    }
    .panel-overlay {
        background: rgba(0,0,0,0);
        display: block;
        opacity: 0;
    }
}

a.tab-link, a.link {
    height: 100%;
    width: 100%;
    box-sizing: border-box;
    .flexbox();
    .justify-content(center);
    .align-items(center);
    overflow: visible;
    -webkit-box-flex: 1;
    -ms-flex: 1;
    -webkit-box-orient: vertical;
    -moz-box-orient: vertical;
    -ms-flex-direction: column;
    -webkit-flex-direction: column;
    flex-direction: column;
}

@media only screen and (min-width: @tabletBreakpoint) and (max-width: @largestTabletScreen) {
  .ui.container {
    width: @tabletWidth;
    margin-left: @tabletGutter !important;
    margin-right: @tabletGutter !important;
  }
  .ui.grid.container {
    width: @tabletGridWidth !important;
  }
  .ui.relaxed.grid.container {
    width: @tabletRelaxedGridWidth !important;
  }
  .ui.very.relaxed.grid.container {
    width: @tabletVeryRelaxedGridWidth !important;
  }
}

&.ui-editable-column {
    .ui-selectonemenu, .ui-inputfield, .ui-autocomplete {
        border-left: transparent!important;
        border-right: transparent!important;
        border-radius: 0!important;
        &.ui-state-hover {
            border-top-color: transparent!important;
            border-bottom-color: transparent!important;
            border-radius: 0!important;
        }
    }
}

ul.ui-selectlistbox-list, ul.ui-multiselectlistbox-list {
    li {
        &.ui-selectlistbox-item, &.ui-multiselectlistbox-item {
            position: relative;
            overflow: hidden;
            padding: 3px 6px;

            &.ui-state-highlight {
                border-radius: @default-border-radius;
            }
        }
        &.ui-listbox-outline {
            outline:none;
        }
    }
}

> a,
    > span {
      position: relative;
      // float: left; // Collapse white-space
      display: block;
      padding: @pagination-padding;
      text-decoration: none;
      line-height: @pagination-line-height;
      background-color: @pagination-bg;
      border: 1px solid @pagination-border;
      border-radius: @global-radius;
      margin-bottom: 5px;
      margin-right: 5px;
    }

& i {
  width: 16px;
  margin-left: 7px;
  background: url(https://zos.alipayobjects.com/rmsportal/dgqoflLasHqTmNM.svg) center no-repeat;
  background-size: contain;
  filter: brightness(1);
  height: 16px;
  display: inline-block;
  vertical-align: sub;
  text-transform: none;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  line-height: 1;
  transition: filter @animate-duration @ease-out;
}

& .home-button a {
  border: 1px solid @text-color-dark;
  color: @text-color-dark;
  border-radius: 21px;
  padding: 8px 24px;
  display: inline-block;
  font-size: 14px;
  box-shadow: 0 0 0 transparent;
  background: transparent;
  transition: box-shadow @animate-duration @ease-out, color @animate-duration @ease-out, background @animate-duration @ease-out;
  &:hover {
    color: @text-color-light;
    background: @text-color-dark;
  }
}

&.disabled,
  &.disabled:hover,
  &.disabled:focus {
    background-color: @list-group-disabled-bg;
    color: @list-group-disabled-color;
    cursor: @cursor-disabled;

    // Force color to inherit for custom content
    .list-group-item-heading {
      color: inherit;
    }
    .list-group-item-text {
      color: @list-group-disabled-text-color;
    }
  }

> a,
    > span {
      position: relative;
      float: left; // Collapse white-space
      padding: @padding-base-vertical @padding-base-horizontal;
      line-height: @line-height-base;
      text-decoration: none;
      color: @pagination-color;
      background-color: @pagination-bg;
      border: 1px solid @pagination-border;
      margin-left: -1px;
    }

progress {
  -webkit-appearance: none;
  height: @progress-height;
  border-radius: @component-border-radius;

  background-color: @input-background-color;
  box-shadow: inset 0 0 0 1px @input-border-color;

  background-image:
     linear-gradient(-45deg, transparent 33%, @progress-buffer-color 33%,
                             @progress-buffer-color 66%, transparent 66%);
  background-size: 25px @progress-height, 100% 100%, 100% 100%;
  -webkit-animation: animate-stripes 5s linear infinite;
}

@-webkit-keyframes source-line-modification-background-fadeout-revised {
	0% {
		background-color: @selection-background;
		outline: 1px solid @selection-border;
	}

	50% {
		background-color: @selection-background;
		outline: 1px solid @selection-border;
	}

	100% {
		background-color: @global-background;
		outline: 1px solid @global-background;
	}
}

li:hover:not(.selected) .selection,
		li.hovered:not(.selected) .selection  {
			display: block !important;
			background: @hover-background !important;
			border-top: 1px solid @hover-border !important;
			border-bottom: 1px solid @hover-border !important;
			margin-top: -1px !important;
			height: 18px !important;
			border-radius: 0 !important;
		}

&:after,
			&:before
			{
				display: block;
				left: 0;
				opacity: 0;
				position: absolute;
				top: 0;

				animation: 1s steps(8) infinite normal running;
				animation-timing-function: linear;
				animation-play-state: running;
				-webkit-animation: 1s steps(8) infinite normal running;
				-webkit-animation-timing-function: linear;
				-webkit-animation-play-state: running;
			}

@media only screen and (min-width: 1200px) and (max-width: 1500px) {
  .ui.grid > .row > [class*="eight wide middle computer"].column,
  .ui.grid > .column.row > [class*="eight wide middle computer"].column,
  .ui.grid > [class*="eight wide middle computer"].column,
  .ui.column.grid > [class*="eight wide middle computer"].column {
    width: 50% !important;
  }
  .ui.grid > .row > [class*="sixteen wide middle computer"].column,
  .ui.grid > .column.row > [class*="sixteen wide middle computer"].column,
  .ui.grid > [class*="sixteen wide middle computer"].column,
  .ui.column.grid > [class*="sixteen wide middle computer"].column {
    width: 100% !important;
  }
}

&::after {
    position: absolute;
    content: "";
    top: 50%;
    left: 50%;
    margin: @loaderMargin;
    width: @loaderSize;
    height: @loaderSize;
    animation: loader @loaderSpeed infinite linear;
    border: @loaderLineWidth solid @loaderLineColor;
    border-radius: @circularRadius;
    box-shadow: 0 0 0 1px transparent;
    visibility: visible;
    z-index: @loaderLineZIndex;
}

@media only screen and (max-width: @largestMobileScreen) {
    .ui.stackable.cards {
        display: block !important;
    }
    .ui.stackable.cards .card:first-child {
        margin-top: 0 !important;
    }
    .ui.stackable.cards > .card {
        display: block !important;
        height: auto !important;
        margin: @stackableRowSpacing @stackableCardSpacing;
        padding: 0 !important;
        width: @stackableMargin !important;
    }
}

@media only screen and (max-width: @largestMobileScreen) {
    .ui.stackable.statistics {
        width: auto;
        margin-left: 0 !important;
        margin-right: 0 !important;
    }
    .ui.stackable.statistics > .statistic {
        width: 100% !important;
        margin: 0 !important;
        padding: (@stackableRowSpacing / 2) (@stackableGutter / 2) !important;
    }
}

dt,
	.warn {
		color: @article-gotcha-text;
		border-color: @article-gotcha-border;
		background-color: @article-gotcha-bg;
		code {
			color: @article-gotcha-code;
			background: @article-gotcha-code-bg;
			border: 1px solid @article-gotcha-code-border;
		}
		pre {
			background: @article-gotcha-code-bg;
			border-color: @article-gotcha-code-border;
			code { border: none; }
		}
	}

atom-text-editor[mini].is-focused,
atom-text-editor[mini].is-focused::shadow {
  border: 1px solid @text-color-highlight;
  background-color: @input-background-color-active;

  &:hover {
    border: 1px solid @text-color-highlight !important;
    background-color: @input-background-color-active !important;
    color: @text-color-highlight !important;
  }

  .selection .region {
    background-color: @theme-dusk !important;
  }
}

&,
    &:hover,
    &:focus {
      z-index: 3;
      color: @pagination-active-color;
      background-color: @pagination-active-bg;
      cursor: @cursor-disabled;

      position: relative;
      float: left; // Collapse white-space
      padding: @padding-base-vertical @padding-base-horizontal;
      line-height: @line-height-base;
      text-decoration: none;
      border: 1px solid @pagination-active-border;
      margin-left: -1px;
    }

&.disabled,
  &.disabled:hover,
  &.disabled:focus {
    color: @list-group-disabled-color;
    cursor: @cursor-disabled;
    background-color: @list-group-disabled-bg;

    // Force color to inherit for custom content
    .list-group-item-heading {
      color: inherit;
    }
    .list-group-item-text {
      color: @list-group-disabled-text-color;
    }
  }

input:-webkit-autofill,
  input:-webkit-autofill:hover,
  input:-webkit-autofill:focus,
  textarea:-webkit-autofill,
  textarea:-webkit-autofill:hover,
  textarea:-webkit-autofill:focus,
  select:-webkit-autofill,
  select:-webkit-autofill:hover,
  select:-webkit-autofill:focus {
    border: 1px solid @border-color-base;
    -webkit-text-fill-color: @text-color;
    box-shadow: none;
    transition: background-color 5000s ease-in-out 0s;
  }

label.label-checkbox input[type="checkbox"]:checked + .item-media i.icon-form-checkbox,
label.label-checkbox input[type="checkbox"]:checked ~ .item-after i.icon-form-checkbox,
label.label-checkbox input[type="checkbox"]:checked ~ .item-inner i.icon-form-checkbox,
label.label-checkbox input[type="radio"]:checked + .item-media i.icon-form-checkbox,
label.label-checkbox input[type="radio"]:checked ~ .item-after i.icon-form-checkbox,
label.label-checkbox input[type="radio"]:checked ~ .item-inner i.icon-form-checkbox,
.form-checkbox input[type="checkbox"]:checked ~ i {
    border-color: @themeColor;
    background-color: @themeColor;
    &:after {
        opacity: 1;
    }
}
